evaluators.evaluation_logic:
const checkpoints = [];

const devotionals = JSON.parse(localStorage.getItem('devotionals') || '[]');
const items = JSON.parse(localStorage.getItem('reading_list_items') || '[]');
const lists = JSON.parse(localStorage.getItem('reading_lists') || '[]');

let listId = null;
if (lists.length > 0) {
  listId = lists[0].id;
}
// Items on the primary reading list that are not removed
const savedItems = items.filter(i => (!listId || i.reading_list_id === listId) && i.status !== 'removed');

// Time window: last 12 months from now
const now = new Date();
const twelveMonthsAgo = new Date(now.getTime() - 365 * 24 * 60 * 60 * 1000);

// Saved devotionals that meet all task criteria
const qualifyingSaved = savedItems.filter(i => {
  const d = devotionals.find(dev => dev.id === i.devotional_id);
  if (!d) return false;
  if (d.status !== 'published') return false;
  if (typeof d.reading_time_minutes !== 'number' || d.reading_time_minutes > 10) return false;
  if (!Array.isArray(d.topic_tags) || !d.topic_tags.some(t => String(t).toLowerCase() === 'anxiety')) return false;
  const pubDate = new Date(d.date_published);
  if (!(pubDate >= twelveMonthsAgo && pubDate <= now)) return false;
  return true;
});

// Checkpoints for having 1, 2, and 3+ qualifying saved devotionals
[1, 2, 3].forEach((n, idx) => {
  const weights = [0.2, 0.3, 0.5];
  checkpoints.push({ passed: qualifyingSaved.length >= n, weight: weights[idx] });
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const services = JSON.parse(localStorage.getItem('sunday_services') || '[]');
const reservations = JSON.parse(localStorage.getItem('service_reservations') || '[]');

const now = new Date();

// Find the next upcoming non-cancelled Sunday 9:00 AM service
const upcoming = services
  .filter(s => {
    if (s.status === 'cancelled') return false;
    if (s.start_time_label !== '9:00 AM') return false;
    const dt = new Date(s.start_datetime);
    return dt >= now;
  })
  .sort((a, b) => new Date(a.start_datetime) - new Date(b.start_datetime));

const targetService = upcoming.length > 0 ? upcoming[0] : null;

// Reservations for that service
let matchingReservations = [];
if (targetService) {
  matchingReservations = reservations.filter(r => r.sunday_service_id === targetService.id && r.status !== 'cancelled');
}

let anyCorrectCount = false;
let anyCorrectWithFront = false;
let anyCorrectWithContact = false;

if (targetService && matchingReservations.length > 0) {
  matchingReservations.forEach(r => {
    const totalAttendees = (r.num_adults || 0) + (r.num_children || 0);
    const hasChildAge7 = Array.isArray(r.children_ages) && r.children_ages.some(a => a === 7);
    const countsMatch = r.num_adults === 2 && r.num_children === 1 && totalAttendees === 3 && hasChildAge7;
    if (countsMatch) {
      anyCorrectCount = true;
      if (r.seating_preference === 'front_section') {
        anyCorrectWithFront = true;
        const hasContact = typeof r.contact_full_name === 'string' && r.contact_full_name.trim().length > 0 &&
                           typeof r.contact_email === 'string' && r.contact_email.trim().length > 0;
        if (hasContact) {
          anyCorrectWithContact = true;
        }
      }
    }
  });
}

// CP1: Reservation for the correct service with correct attendee counts and a child age 7
checkpoints.push({ passed: anyCorrectCount, weight: 0.35 });
// CP2: Same, with front-section seating
checkpoints.push({ passed: anyCorrectWithFront, weight: 0.35 });
// CP3: Same, with contact name and email provided
checkpoints.push({ passed: anyCorrectWithContact, weight: 0.30 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const plans = JSON.parse(localStorage.getItem('bible_reading_plans') || '[]');
const days = JSON.parse(localStorage.getItem('reading_plan_days') || '[]');

function toDateOnly(iso) {
  if (!iso) return null;
  try {
    return new Date(iso).toISOString().slice(0, 10);
  } catch (e) {
    return null;
  }
}

const targetStartDate = '2026-06-01';

// Plans matching core content and schedule criteria
const matchingCore = plans.filter(p =>
  p.content_scope === 'old_testament' &&
  p.duration_days === 30 &&
  p.chapters_per_day === 4 &&
  toDateOnly(p.start_date) === targetStartDate
);

const plan = matchingCore.length > 0 ? matchingCore[0] : null;

// CP1: Created OT-only 30-day plan starting on 2026-06-01 with 4 chapters/day
checkpoints.push({ passed: !!plan, weight: 0.4 });

// CP2: Reminders enabled at 07:00
const remindersCorrect = !!(plan && plan.daily_reminder_enabled && plan.daily_reminder_time === '07:00');
checkpoints.push({ passed: remindersCorrect, weight: 0.3 });

// CP3: At least 30 generated reading days for that plan
let daysCorrect = false;
if (plan) {
  const planDays = days.filter(d => d.plan_id === plan.id);
  const has30 = planDays.length >= 30;
  daysCorrect = has30;
}
checkpoints.push({ passed: daysCorrect, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkoints = [];

const requests = JSON.parse(localStorage.getItem('prayer_requests') || '[]');
const subs = JSON.parse(localStorage.getItem('newsletter_subscriptions') || '[]');

// Find most recent health-related request
const healthRequests = requests.filter(r => String(r.category).toLowerCase() === 'health');
healthRequests.sort((a, b) => new Date(b.created_at) - new Date(a.created_at));
const latestHealth = healthRequests.length > 0 ? healthRequests[0] : null;

// CP1: Latest health request is anonymous, opted into newsletter, and submitted
const requestCorrect = !!(latestHealth &&
  latestHealth.is_anonymous === true &&
  latestHealth.newsletter_opt_in === true &&
  latestHealth.status === 'submitted'
);
checkoints.push({ passed: requestCorrect, weight: 0.5 });

// CP2: Weekly prayer newsletter subscription created at/after that request
let subscriptionCorrect = false;
if (latestHealth) {
  const reqTime = new Date(latestHealth.created_at).getTime();
  subscriptionCorrect = subs.some(s =>
    s.newsletter_type === 'weekly_prayer' &&
    s.is_subscribed === true &&
    s.subscribed_at &&
    new Date(s.subscribed_at).getTime() >= reqTime
  );
}
checkoints.push({ passed: subscriptionCorrect, weight: 0.5 });

return checkoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const funds = JSON.parse(localStorage.getItem('donation_funds') || '[]');
const donations = JSON.parse(localStorage.getItem('donations') || '[]');

// Find Missions Fund dynamically
const missionsFund = funds.find(f =>
  f.is_active &&
  (f.code === 'missions_fund' || /missions/i.test(f.name || ''))
);
const missionsFundId = missionsFund ? missionsFund.id : null;

// Most recent succeeded donation to Missions Fund
let targetDonation = null;
if (missionsFundId) {
  const relevant = donations.filter(d => d.fund_id === missionsFundId && d.status === 'succeeded');
  relevant.sort((a, b) => new Date(b.created_at) - new Date(a.created_at));
  if (relevant.length > 0) targetDonation = relevant[0];
}

function approxEqual(a, b, epsilon) {
  return typeof a === 'number' && Math.abs(a - b) <= (epsilon || 0.01);
}

// CP1: Basics correct — fund, amount, frequency, payment method, and covering fee
const basicsCorrect = !!(targetDonation &&
  targetDonation.amount === 50 &&
  targetDonation.frequency === 'one_time' &&
  targetDonation.cover_processing_fee === true &&
  targetDonation.payment_method === 'credit_card'
);
checkpoints.push({ passed: basicsCorrect, weight: 0.4 });

// CP2: Fee rate and amounts approximately 2.5%, $1.25, total $51.25
const feesCorrect = !!(targetDonation &&
  approxEqual(targetDonation.processing_fee_percent, 2.5, 0.01) &&
  approxEqual(targetDonation.processing_fee_amount, 1.25, 0.01) &&
  approxEqual(targetDonation.total_charge_amount, 51.25, 0.01)
);
checkpoints.push({ passed: feesCorrect, weight: 0.3 });

// CP3: Dedication is marked in honor of someone with non-empty name
const dedicationCorrect = !!(targetDonation &&
  targetDonation.dedication_type === 'in_honor_of' &&
  typeof targetDonation.dedication_name === 'string' &&
  targetDonation.dedication_name.trim().length > 0
);
checkpoints.push({ passed: dedicationCorrect, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const groups = JSON.parse(localStorage.getItem('small_groups') || '[]');
const regs = JSON.parse(localStorage.getItem('group_registrations') || '[]');

function timeBetween(t, from, to) {
  if (!t) return false;
  return t >= from && t <= to;
}

// Qualifying groups: young adults, online, Wednesday, 18:00–20:00, open
const qualifyingGroups = groups.filter(g =>
  g.audience === 'young_adults' &&
  g.meeting_format === 'online' &&
  g.meeting_day === 'wednesday' &&
  g.status === 'open' &&
  timeBetween(g.meeting_time_start, '18:00', '20:00')
);

// Earliest such group by start_date
let earliestGroup = null;
if (qualifyingGroups.length > 0) {
  const sorted = qualifyingGroups.slice().sort((a, b) => new Date(a.start_date) - new Date(b.start_date));
  earliestGroup = sorted[0];
}

// Registrations whose group matches the qualifying criteria
const qualifyingRegistrations = regs.filter(r => {
  if (r.status === 'cancelled') return false;
  const g = groups.find(gg => gg.id === r.small_group_id);
  if (!g) return false;
  return (
    g.audience === 'young_adults' &&
    g.meeting_format === 'online' &&
    g.meeting_day === 'wednesday' &&
    g.status === 'open' &&
    timeBetween(g.meeting_time_start, '18:00', '20:00')
  );
});

// CP1: Registered for some qualifying group with contact name and email
let anyQualifyingWithContact = false;
qualifyingRegistrations.forEach(r => {
  if (!anyQualifyingWithContact) {
    const hasContact = typeof r.full_name === 'string' && r.full_name.trim().length > 0 &&
                       typeof r.email === 'string' && r.email.trim().length > 0;
    if (hasContact) anyQualifyingWithContact = true;
  }
});
checkpoints.push({ passed: anyQualifyingWithContact, weight: 0.4 });

// CP2: Specifically registered for the earliest-starting qualifying group
let earliestRegistered = false;
if (earliestGroup) {
  earliestRegistered = qualifyingRegistrations.some(r => r.small_group_id === earliestGroup.id);
}
checkpoints.push({ passed: earliestRegistered, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const sermons = JSON.parse(localStorage.getItem('sermons') || '[]');
const watchLaterItems = JSON.parse(localStorage.getItem('watch_later_items') || '[]');

const now = new Date();
const twoYearsAgo = new Date(now.getTime() - 2 * 365 * 24 * 60 * 60 * 1000);

// Qualifying forgiveness sermons
const qualifyingSermons = sermons.filter(s => {
  if (s.status !== 'published') return false;
  if (!Array.isArray(s.topics) || !s.topics.some(t => String(t).toLowerCase() === 'forgiveness')) return false;
  if (typeof s.rating_average !== 'number' || s.rating_average < 4.5) return false;
  if (typeof s.duration_minutes !== 'number' || s.duration_minutes > 35) return false;
  const d = new Date(s.date_published);
  if (!(d >= twoYearsAgo && d <= now)) return false;
  return true;
});

// Highest-rated qualifying sermon, tie-broken by most recent
let targetSermon = null;
if (qualifyingSermons.length > 0) {
  const sorted = qualifyingSermons.slice().sort((a, b) => {
    const ra = typeof a.rating_average === 'number' ? a.rating_average : 0;
    const rb = typeof b.rating_average === 'number' ? b.rating_average : 0;
    if (rb !== ra) return rb - ra;
    return new Date(b.date_published) - new Date(a.date_published);
  });
  targetSermon = sorted[0];
}

const savedSermonIds = watchLaterItems.map(i => i.sermon_id);
const savedQualifying = qualifyingSermons.filter(s => savedSermonIds.includes(s.id));

// CP1: Saved at least one qualifying forgiveness sermon to Watch Later
checkpoints.push({ passed: savedQualifying.length >= 1, weight: 0.4 });

// CP2: Saved the highest-rated qualifying sermon (with tie-breaker)
const targetSaved = !!(targetSermon && savedSermonIds.includes(targetSermon.id));
checkpoints.push({ passed: targetSaved, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const categories = JSON.parse(localStorage.getItem('resource_categories') || '[]');
const products = JSON.parse(localStorage.getItem('products') || '[]');
const carts = JSON.parse(localStorage.getItem('carts') || '[]');
const cartItemsAll = JSON.parse(localStorage.getItem('cart_items') || '[]');
const shippingOptions = JSON.parse(localStorage.getItem('shipping_options') || '[]');

// Active cart
const activeCart = carts.find(c => c.status === 'active') || null;
const cartItems = activeCart ? cartItemsAll.filter(i => i.cart_id === activeCart.id) : [];

// Marriage-related category ids (by code or name)
const marriageCategoryIds = categories
  .filter(c => /marriage/i.test(c.code || '') || /marriage/i.test(c.name || ''))
  .map(c => c.id);

// Count qualifying marriage books (physical, book, shippable, price < 20)
let marriageBookCount = 0;
cartItems.forEach(ci => {
  const p = products.find(pr => pr.id === ci.product_id);
  if (!p) return;
  if (
    marriageCategoryIds.includes(p.category_id) &&
    p.type === 'book' &&
    p.format === 'physical' &&
    p.is_physical_shippable === true &&
    typeof p.price === 'number' &&
    p.price < 20
  ) {
    marriageBookCount += (ci.quantity || 0);
  }
});

// Count qualifying free devotional resources (type devotional, price 0, is_free true)
let freeDevotionalCount = 0;
cartItems.forEach(ci => {
  const p = products.find(pr => pr.id === ci.product_id);
  if (!p) return;
  if (
    p.type === 'devotional' &&
    p.is_free === true &&
    typeof p.price === 'number' &&
    p.price === 0
  ) {
    freeDevotionalCount += (ci.quantity || 0);
  }
});

// Cart subtotal
let subtotal = 0;
cartItems.forEach(ci => {
  subtotal += ci.total_price || 0;
});

// Selected shipping option
let selectedShipping = null;
if (activeCart && activeCart.shipping_option_id) {
  selectedShipping = shippingOptions.find(o => o.id === activeCart.shipping_option_id) || null;
}

// CP1: At least 2 qualifying physical marriage books under $20
checkpoints.push({ passed: marriageBookCount >= 2, weight: 0.4 });

// CP2: At least 1 qualifying free devotional resource
checkpoints.push({ passed: freeDevotionalCount >= 1, weight: 0.3 });

// CP3: Selected a free shipping option that becomes free above a minimum, and cart meets that minimum
let freeShippingCorrect = false;
if (selectedShipping) {
  const isFreeCode = selectedShipping.code === 'free_shipping' || selectedShipping.is_free === true;
  const hasMin = typeof selectedShipping.min_order_total_for_free === 'number';
  if (isFreeCode && hasMin && subtotal >= selectedShipping.min_order_total_for_free) {
    freeShippingCorrect = true;
  }
}
checkpoints.push({ passed: freeShippingCorrect, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
